import React from 'react';
import { Card, CardContent, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Quote {
  text: string;
  author: string;
  category: string;
}

interface QuoteData {
  quote: Quote;
}

export default function Widget() {
  const { quote } = response.data as QuoteData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 280, maxWidth: 380, bgcolor: theme === 'light' ? '#FFFFFF' : '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: primaryColor, fontWeight: 600 }}>
            Quote of the Day
          </Typography>
          <Typography variant="body1" sx={{ color: '#4B5563' }}>
            "{quote.text}"
          </Typography>
          <Typography variant="body2" sx={{ color: '#9CA3AF', textAlign: 'right' }}>
            - {quote.author}
          </Typography>
          <Stack direction="row" spacing={0.5}>
            <Chip label={quote.category} sx={{ backgroundColor: accentColor, color: '#FFFFFF', fontSize: '11px', px: 1, py: 0.5 }} />
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
